-- ============================================
-- Legislacao full-site: felicio-ramuth / SP ALESP / legislacao_mandato_executivo
-- Seed ampliado parcial: Lote A leis sancionadas pelo Vice-Governador em exercicio
-- ============================================
-- Fonte oficial: Assembleia Legislativa do Estado de Sao Paulo - Repositorio de Legislacao
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = felicio-ramuth-sp-alesp-vice-ampliado-parcial-lote-a-20260505
--   coverage_scope = inventario_ampliado_parcial_sp_alesp_vice_exercicio_lote_a_20260505
--
-- Filtro factual: paginas oficiais ALESP com numero, data, ementa,
-- formula "O VICE-GOVERNADOR, EM EXERCICIO NO CARGO DE GOVERNADOR DO ESTADO DE SAO PAULO",
-- assinatura Felicio Ramuth e Palacio dos Bandeirantes.
-- Nao e inventario completo de Sao Paulo nem do mandato municipal de Sao Jose dos Campos.
--
-- Esta migration NAO escreve em projetos_lei.
-- Esta migration NAO escreve em historico_politico.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  lme_total int;
  target_count int;
  mandato_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'felicio-ramuth';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'felicio-ramuth: candidato ausente neste banco local/CI minimo; seed LME SP ALESP pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO lme_total
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'felicio-ramuth-sp-alesp-vice-ampliado-parcial-lote-a-20260505';

  IF lme_total NOT IN (0, 66) THEN
    RAISE EXCEPTION 'Pre-condicao felicio-ramuth: esperadas 0 rows atuais ou 66 rows alvo idempotentes em legislacao_mandato_executivo, encontradas %', lme_total;
  END IF;

  IF lme_total = 66 AND target_count <> 66 THEN
    RAISE EXCEPTION 'Pre-condicao felicio-ramuth: 66 rows existentes, mas apenas % com coverage_id alvo', target_count;
  END IF;

  SELECT count(*) INTO mandato_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Vice-Governador%' OR hp.cargo_canonico = 'Vice-Governador')
    AND UPPER(COALESCE(hp.estado, '')) = 'SP'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2023
    AND COALESCE(hp.periodo_fim, 9999) >= 2023;

  IF mandato_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao felicio-ramuth: mandato Vice-Governador/SP 2023+ nao encontrado em historico_politico';
  END IF;
END $$;

